def gen(rng, size):
    def num(maxlen):
        L = rng.randint(1, max(1, maxlen))
        digs = [str(rng.randint(1, 9))] + [str(rng.randint(0, 9)) for _ in range(L - 1)]
        return ''.join(digs)
    return [num(size), num(size)]

